Here's how to test `DataFetcher` with MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.NotFound
        });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // framework enforces 5s ceiling
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast")
        });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass TestContext.CancellationToken so [Timeout] can
        // cancel the call cooperatively if it runs too long
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Minimal fake handler — avoids real network calls
    private sealed class FakeHttpMessageHandler(
        HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key takeaways:**

| Pattern | Why |
|---|---|
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you inspect the exception and won't silently pass on wrong exception types |
| `TestContext.CancellationToken` | Enables **cooperative cancellation** with `[Timeout]` — without it the timeout can't stop an in-flight `await` |
| `FakeHttpMessageHandler` | Overrides `SendAsync` to avoid real HTTP; calls `ThrowIfCancellationRequested()` to honor cancellation like a real handler |
| Constructor-injected `TestContext` | Enables `readonly` fields and satisfies nullability analyzers (MSTest 3.6+) |
| `sealed` test class | Best practice for performance and design clarity |
